const sourceWorkflow = $json.source_workflow || 'UNKNOWN';
const errorMessage = $json.error_message || 'Unspecified error';
const errorFamily = $json.error_family || 'SE-P1-001';
const errorMapping = {
  'SE-P1-001': { category: 'intake_error', replayable: false, manualReviewRequired: true, retryAllowed: false, suggestedTarget: 'WF-010' },
  'SE-P1-002': { category: 'health_check_error', replayable: false, manualReviewRequired: true, retryAllowed: false, suggestedTarget: 'WF-000' },
  'SE-P1-003': { category: 'orchestration_error', replayable: true, manualReviewRequired: false, retryAllowed: true, suggestedTarget: 'WF-010' },
  'DEFAULT': { category: 'unknown_error', replayable: false, manualReviewRequired: true, retryAllowed: false, suggestedTarget: 'WF-010' }
};
const mappedError = errorMapping[errorFamily] || errorMapping['DEFAULT'];
const remediationTarget = $json.replay_target_workflow || mappedError.suggestedTarget;
return [{
  json: {
    ...$json,
    error_resolution: {
      error_family: errorFamily,
      category: mappedError.category,
      is_replayable: mappedError.replayable,
      manual_review_required: mappedError.manualReviewRequired,
      retry_allowed: mappedError.retryAllowed,
      suggested_remediation_target: remediationTarget,
      remediation_timestamp: new Date().toISOString()
    }
  }
}];

try {
  const resolution = $json.error_resolution;
  if (!resolution || !resolution.error_family) {
    throw new Error('missing error resolution fields');
  }
  return [{ json: { ...$json, validation_status: 'SUCCESS', route_to_error: false } }];
} catch (error) {
  return [{ json: { ...$json, validation_status: 'FAILED', route_to_error: true, validation_error: String(error.message || error) } }];
}

if ($json.route_to_error) return [];
return [{
  json: {
    ...$json,
    se_error_events_write: {
      operation: 'create_error_event',
      error_id: 'ERR-' + Date.now(),
      dossier_id: $json.dossier_id,
      source_workflow: $json.source_workflow,
      error_family: $json.error_resolution.error_family,
      error_message: $json.error_message,
      error_category: $json.error_resolution.category,
      is_replayable: $json.error_resolution.is_replayable,
      manual_review_required: $json.error_resolution.manual_review_required,
      timestamp: new Date().toISOString(),
      writeback_target: 'se_error_events'
    }
  }
}];

if ($json.route_to_error) return [];
if (!$json.error_resolution.is_replayable || $json.error_resolution.manual_review_required) return [];
return [{
  json: {
    ...$json,
    replay_instruction: {
      operation: 'auto_replay',
      target_workflow: $json.error_resolution.suggested_remediation_target,
      replay_type: 'FROM_CHECKPOINT',
      dossier_id: $json.dossier_id,
      original_error_id: 'ERR-' + Date.now(),
      replay_timestamp: new Date().toISOString()
    }
  }
}];

if ($json.route_to_error) return [];
if ($json.error_resolution.is_replayable && !$json.error_resolution.manual_review_required) return [];
return [{
  json: {
    ...$json,
    se_approval_queue_write: {
      operation: 'queue_for_approval',
      dossier_id: $json.dossier_id,
      approval_type: 'manual_error_review',
      error_family: $json.error_resolution.error_family,
      error_message: $json.error_message,
      suggested_target: $json.error_resolution.suggested_remediation_target,
      requires_founder_approval: $json.error_resolution.category === 'unknown_error',
      queued_at: new Date().toISOString(),
      writeback_target: 'se_approval_queue'
    }
  }
}];

if ($json.route_to_error) return [];
const replayInstruction = $json.replay_instruction || null;
const requiresApproval = $json.se_approval_queue_write || null;
let nextWorkflow = 'WF-010';
let decision = 'MANUAL_REVIEW_REQUIRED';
if (replayInstruction && replayInstruction.operation === 'auto_replay') {
  nextWorkflow = replayInstruction.target_workflow;
  decision = 'AUTO_REPLAY_SCHEDULED';
}
if (requiresApproval) {
  nextWorkflow = 'WF-021';
  decision = 'AWAITING_APPROVAL';
}
return [{
  json: {
    ...$json,
    routing_decision: {
      next_workflow: nextWorkflow,
      decision: decision,
      wf900_bound: true
    }
  }
}];

if (!$json.route_to_error) return [];
return [{
  json: {
    workflow_id: 'WF-900',
    routing_decision: 'FATAL_ERROR',
    next_workflow: 'NONE',
    error_message: $json.validation_error || 'WF-900 internal error',
    manual_operator_review_required: true
  }
}];

return [{
  json: {
    workflow_id: 'WF-900',
    execution_status: 'COMPLETE',
    completion_packet: {
      instance_id: 'WF-900-COMP-' + Date.now(),
      artifact_family: 'error_resolution_packet',
      schema_version: '1.0.0',
      producer_workflow: 'WF-900',
      dossier_ref: $json.dossier_id,
      created_at: new Date().toISOString(),
      status: 'CREATED',
      payload: {
        error_family: $json.error_resolution?.error_family || 'UNKNOWN',
        resolution_type: $json.routing_decision?.decision || 'MANUAL_REVIEW_REQUIRED',
        next_workflow: $json.routing_decision?.next_workflow || 'WF-010',
        approval_required: $json.se_approval_queue_write ? true : false
      }
    }
  }
}];
